#include <expected>
#include <iostream>
#include <string>
#include <string_view>

std::expected<int, std::string> parse_int(std::string_view s) {
    if (s.empty()) return std::unexpected(std::string("empty input"));
    for (char c : s)
        if (c < '0' || c > '9') return std::unexpected(std::string("not a number: ") + c);
    int result = 0;
    for (char c : s) result = result * 10 + (c - '0');
    return result;
}

int main() {
    auto r1 = parse_int("123");
    auto r2 = parse_int("");
    auto r3 = parse_int("12x");

    if (r1) std::cout << "ok: " << *r1 << "\n";
    if (!r2) std::cout << "err: " << r2.error() << "\n";
    if (!r3) std::cout << "err: " << r3.error() << "\n";
}

#include <expected>
#include <iostream>
#include <string>
#include <string_view>

enum class Error { empty, not_number, out_of_range };

std::expected<int, Error> parse(std::string_view s) {
    if (s.empty()) return std::unexpected(Error::empty);
    for (char c : s)
        if (c < '0' || c > '9') return std::unexpected(Error::not_number);
    long long v = 0;
    for (char c : s) v = v * 10 + (c - '0');
    if (v > 100) return std::unexpected(Error::out_of_range);
    return static_cast<int>(v);
}

std::expected<int, Error> double_it(std::string_view s) {
    auto r = parse(s);
    if (!r) return r; // propagate error
    return *r * 2;
}

std::string describe(Error e) {
    switch (e) {
        case Error::empty:        return "empty";
        case Error::not_number:   return "not a number";
        case Error::out_of_range: return "out of range";
    }
    return "unknown";
}

int main() {
    for (auto s : {"42", "abc", "200", ""}) {
        auto r = double_it(s);
        if (r) std::cout << s << " -> " << *r << "\n";
        else   std::cout << s << " -> error: " << describe(r.error()) << "\n";
    }
}

#include <expected>
#include <iostream>
#include <string>

std::expected<double, std::string> safe_divide(double a, double b) {
    if (b == 0.0) return std::unexpected(std::string("division by zero"));
    return a / b;
}

int main() {
    // value_or для безопасного значения по умолчанию
    auto r1 = safe_divide(10.0, 2.0);
    auto r2 = safe_divide(10.0, 0.0);
    std::cout << r1.value_or(-1.0) << "\n";
    std::cout << r2.value_or(-1.0) << "\n";

    // исключение из .value() при ошибочном состоянии
    try {
        r2.value();
    } catch (const std::bad_expected_access<std::string>& e) {
        std::cout << "caught: " << e.error() << "\n";
    }
}

lessons.motivation:
Паттерн раннего возврата из m3-l1 работает, но при нескольких последовательных шагах быстро становится многословным:

auto r1 = step1(input);
if (!r1) return std::unexpected(r1.error());
auto r2 = step2(*r1);
if (!r2) return std::unexpected(r2.error());
auto r3 = step3(*r2);
if (!r3) return std::unexpected(r3.error());

Каждый шаг требует отдельной проверки и явного разыменования. C++23 добавляет к std::expected монадические операции — and_then, transform, or_else и transform_error — которые позволяют записать ту же логику как чистый конвейер без промежуточных переменных и ручных проверок.

