#include <expected>
#include <iostream>
#include <string>
#include <charconv>

std::expected<int, std::string> parse(std::string_view s) {
    int v{};
    auto [ptr, ec] = std::from_chars(s.begin(), s.end(), v);
    if (ec != std::errc{}) return std::unexpected(std::string("parse error"));
    return v;
}

std::expected<int, std::string> validate(int v) {
    if (v < 0) return std::unexpected(std::string("negative"));
    if (v > 1000) return std::unexpected(std::string("too large"));
    return v;
}

int main() {
    auto process = [](std::string_view s) {
        return parse(s)
            .and_then(validate)
            .transform([](int v) { return v * 2; });
    };

    for (auto s : {"42", "-5", "2000", "abc"}) {
        auto r = process(s);
        if (r) std::cout << s << " -> " << *r << "\n";
        else   std::cout << s << " -> error: " << r.error() << "\n";
    }
}

#include <expected>
#include <iostream>
#include <string>

enum class AppError { not_found, invalid, network };

std::string to_string(AppError e) {
    switch (e) {
        case AppError::not_found: return "not found";
        case AppError::invalid:   return "invalid";
        case AppError::network:   return "network error";
    }
    return "unknown";
}

std::expected<int, AppError> fetch(bool fail) {
    if (fail) return std::unexpected(AppError::network);
    return 42;
}

int main() {
    // or_else: восстановиться из сетевой ошибки значением по умолчанию
    auto r = fetch(true)
        .or_else([](AppError e) -> std::expected<int, AppError> {
            if (e == AppError::network) return 0; // умолчание при network error
            return std::unexpected(e); // остальные ошибки пробрасываем дальше
        });
    std::cout << "recovered: " << *r << "\n";

    // transform_error: конвертировать тип ошибки в строку
    auto r2 = fetch(true)
        .transform_error([](AppError e) { return to_string(e); });
    std::cout << "error as string: " << r2.error() << "\n";
}

#include <expected>
#include <optional>
#include <iostream>
#include <string>
#include <charconv>

// конвейер на expected
std::expected<int, std::string> parse_int(std::string_view s) {
    int v{};
    auto [ptr, ec] = std::from_chars(s.begin(), s.end(), v);
    if (ec != std::errc{}) return std::unexpected(std::string("not a number"));
    return v;
}

// конвейер на optional (монадические операции добавлены в C++23)
std::optional<int> try_parse(std::string_view s) {
    int v{};
    auto [ptr, ec] = std::from_chars(s.begin(), s.end(), v);
    if (ec != std::errc{}) return std::nullopt;
    return v;
}

int main() {
    // expected: полная информация об ошибке сохраняется
    auto r = parse_int("21")
        .and_then([](int v) -> std::expected<int, std::string> {
            if (v == 0) return std::unexpected(std::string("zero"));
            return v;
        })
        .transform([](int v) { return v * 2; });
    std::cout << "expected result: " << *r << "\n";

    // optional: та же форма, но без информации об ошибке
    auto o = try_parse("21")
        .and_then([](int v) -> std::optional<int> {
            if (v == 0) return std::nullopt;
            return v;
        })
        .transform([](int v) { return v * 2; });
    std::cout << "optional result: " << *o << "\n";
}
